import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.Job
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class ChatMessage(val role: String, val text: String)

data class ChatUiState(
    val messages: List<ChatMessage> = emptyList(),
    val streamingText: String = "",
    val isStreaming: Boolean = false,
    val error: String? = null
)

class ChatViewModel(private val repository: ClaudeRepository) : ViewModel() {

    private val _uiState = MutableStateFlow(ChatUiState())
    val uiState: StateFlow<ChatUiState> = _uiState.asStateFlow()

    private var streamJob: Job? = null

    fun sendMessage(text: String) {
        if (text.isBlank() || _uiState.value.isStreaming) return
        streamJob = viewModelScope.launch {
            _uiState.update { it.copy(
                messages = it.messages + ChatMessage("user", text),
                streamingText = "",
                isStreaming = true,
                error = null
            ) }

            repository.streamMessage(text).collect { event ->
                when (event) {
                    is ClaudeStreamEvent.Token ->
                        _uiState.update { it.copy(streamingText = it.streamingText + event.text) }
                    is ClaudeStreamEvent.StreamEnd -> {
                        val fullText = _uiState.value.streamingText
                        _uiState.update { it.copy(
                            messages = it.messages + ChatMessage("assistant", fullText),
                            streamingText = "",
                            isStreaming = false
                        ) }
                    }
                    is ClaudeStreamEvent.Error ->
                        _uiState.update { it.copy(
                            streamingText = "",
                            isStreaming = false,
                            error = event.message
                        ) }
                }
            }
        }
    }

    fun cancelStream() {
        streamJob?.cancel()
        _uiState.update { it.copy(isStreaming = false, streamingText = "") }
    }

    fun dismissError() = _uiState.update { it.copy(error = null) }
}

import androidx.lifecycle.compose.collectAsStateWithLifecycle

@Composable
fun ChatScreen(viewModel: ChatViewModel) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    // uiState.messages, uiState.streamingText, uiState.isStreaming are all live
}

import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.rememberLazyListState
import androidx.compose.foundation.lazy.items

@Composable
fun MessageList(
    messages: List<ChatMessage>,
    streamingText: String,
    isStreaming: Boolean,
    modifier: Modifier = Modifier
) {
    val listState = rememberLazyListState()

    // Total item count includes the in-progress assistant bubble when streaming
    val itemCount = messages.size + if (isStreaming || streamingText.isNotEmpty()) 1 else 0

    LaunchedEffect(itemCount) {
        if (itemCount > 0) {
            listState.animateScrollToItem(itemCount - 1)
        }
    }

    LazyColumn(
        state = listState,
        modifier = modifier,
        contentPadding = PaddingValues(vertical = 8.dp)
    ) {
        items(messages, key = { it.hashCode().toString() }) { msg ->
            MessageBubble(role = msg.role, text = msg.text, isStreaming = false)
        }
        if (isStreaming || streamingText.isNotEmpty()) {
            item(key = "streaming") {
                MessageBubble(
                    role = "assistant",
                    text = streamingText,
                    isStreaming = isStreaming
                )
            }
        }
    }
}

import androidx.compose.animation.core.*
import androidx.compose.ui.draw.alpha

@Composable
fun MessageBubble(
    role: String,
    text: String,
    isStreaming: Boolean,
    modifier: Modifier = Modifier
) {
    val isUser = role == "user"

    // Only animate when the assistant is actively typing
    val cursorAlpha: Float = if (isStreaming) {
        val infiniteTransition = rememberInfiniteTransition(label = "cursor")
        infiniteTransition.animateFloat(
            initialValue = 1f,
            targetValue = 0f,
            animationSpec = infiniteRepeatable(
                animation = tween(durationMillis = 500, easing = LinearEasing),
                repeatMode = RepeatMode.Reverse
            ),
            label = "cursorAlpha"
        ).value
    } else 0f

    Row(
        modifier = modifier.fillMaxWidth().padding(horizontal = 12.dp, vertical = 4.dp),
        horizontalArrangement = if (isUser) Arrangement.End else Arrangement.Start
    ) {
        Surface(
            shape = MaterialTheme.shapes.medium,
            color = if (isUser) MaterialTheme.colorScheme.primaryContainer
                    else MaterialTheme.colorScheme.surfaceVariant,
            modifier = Modifier.widthIn(max = 300.dp)
        ) {
            Row(
                modifier = Modifier.padding(horizontal = 12.dp, vertical = 8.dp),
                verticalAlignment = Alignment.Bottom
            ) {
                Text(
                    text = text,
                    style = MaterialTheme.typography.bodyMedium
                )
                if (isStreaming) {
                    Text(
                        text = "|",
                        style = MaterialTheme.typography.bodyMedium,
                        modifier = Modifier.alpha(cursorAlpha)
                    )
                }
            }
        }
    }
}

@Composable
fun InputRow(
    isStreaming: Boolean,
    onSend: (String) -> Unit,
    onStop: () -> Unit,
    modifier: Modifier = Modifier
) {
    var text by remember { mutableStateOf("") }

    Row(
        modifier = modifier
            .fillMaxWidth()
            .padding(horizontal = 12.dp, vertical = 8.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        OutlinedTextField(
            value = text,
            onValueChange = { text = it },
            modifier = Modifier.weight(1f),
            placeholder = { Text("Ask Claude...") },
            enabled = !isStreaming,
            maxLines = 4,
            keyboardOptions = KeyboardOptions(imeAction = ImeAction.Send),
            keyboardActions = KeyboardActions(onSend = {
                onSend(text); text = ""
            })
        )
        Spacer(Modifier.width(8.dp))
        if (isStreaming) {
            IconButton(onClick = onStop) {
                Icon(
                    imageVector = Icons.Default.Stop,
                    contentDescription = "Stop generation",
                    tint = MaterialTheme.colorScheme.error
                )
            }
        } else {
            IconButton(
                onClick = { onSend(text); text = "" },
                enabled = text.isNotBlank()
            ) {
                Icon(Icons.Default.Send, contentDescription = "Send")
            }
        }
    }
}

@Composable
fun ChatScreen(viewModel: ChatViewModel = viewModel()) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()

    Scaffold { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
        ) {
            MessageList(
                messages = uiState.messages,
                streamingText = uiState.streamingText,
                isStreaming = uiState.isStreaming,
                modifier = Modifier.weight(1f)
            )

            // Error banner
            uiState.error?.let { errorMsg ->
                Surface(
                    color = MaterialTheme.colorScheme.errorContainer,
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Row(
                        modifier = Modifier.padding(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = errorMsg,
                            color = MaterialTheme.colorScheme.onErrorContainer,
                            modifier = Modifier.weight(1f),
                            style = MaterialTheme.typography.bodySmall
                        )
                        TextButton(onClick = viewModel::dismissError) { Text("OK") }
                    }
                }
            }

            InputRow(
                isStreaming = uiState.isStreaming,
                onSend = viewModel::sendMessage,
                onStop = viewModel::cancelStream
            )
        }
    }
}

import app.cash.turbine.test
import kotlinx.coroutines.flow.flowOf
import kotlinx.coroutines.test.runTest
import org.junit.Assert.*
import org.junit.Test

class ChatViewModelTest {

    @Test
    fun `tokens accumulate and isStreaming flips to false on StreamEnd`() = runTest {
        val fakeRepo = object : ClaudeRepository {
            override fun streamMessage(text: String) = flowOf(
                ClaudeStreamEvent.Token("Hello"),
                ClaudeStreamEvent.Token(" world"),
                ClaudeStreamEvent.StreamEnd
            )
        }
        val viewModel = ChatViewModel(fakeRepo)

        viewModel.uiState.test {
            assertEquals(awaitItem(), ChatUiState())  // initial

            viewModel.sendMessage("Hi")

            // After send: user message added, streaming starts
            val afterSend = awaitItem()
            assertTrue(afterSend.isStreaming)
            assertEquals("Hi", afterSend.messages.last().text)

            // First token
            assertEquals("Hello", awaitItem().streamingText)

            // Second token accumulated
            assertEquals("Hello world", awaitItem().streamingText)

            // StreamEnd: message committed, streaming stops
            val done = awaitItem()
            assertFalse(done.isStreaming)
            assertEquals("", done.streamingText)
            assertEquals("Hello world", done.messages.last().text)

            cancelAndIgnoreRemainingEvents()
        }
    }
}
